-- Função: get_performance_dia_semana
CREATE OR REPLACE FUNCTION public.get_performance_dia_semana(p_bar_id integer, p_ano integer) RETURNS TABLE(dia text, faturamento numeric, clientes bigint, ticketmedio numeric, eventos bigint) LANGUAGE plpgsql SET search_path TO 'public', 'pg_temp'
AS $$ BEGIN RETURN QUERY SELECT CASE EXTRACT(DOW FROM e.data_evento) WHEN 0 THEN 'Domingo' WHEN 1 THEN 'Segunda' WHEN 2 THEN 'Terça' WHEN 3 THEN 'Quarta' WHEN 4 THEN 'Quinta' WHEN 5 THEN 'Sexta' WHEN 6 THEN 'Sábado' END::TEXT, ROUND(SUM(e.faturamento_liquido), 2)::NUMERIC, SUM(e.publico_real)::BIGINT, ROUND(AVG(e.t_medio), 2)::NUMERIC, COUNT(*)::BIGINT FROM eventos e WHERE e.bar_id = p_bar_id AND EXTRACT(YEAR FROM e.data_evento) = p_ano GROUP BY EXTRACT(DOW FROM e.data_evento) ORDER BY EXTRACT(DOW FROM e.data_evento); END; $$;
